def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    # Check if any slides were added or removed
    if len(ppt_diff.added_slides) > 0 or len(ppt_diff.removed_slides) > 0:
        return f"Slides were added or removed: {len(ppt_diff.added_slides)} added, {len(ppt_diff.removed_slides)} removed", 0.0

    # Check if slides other than slide 2 were modified
    modified_other_slides = []
    for old_slide, new_slide in ppt_diff.modified_slides:
        if old_slide.slide_number != 2:
            modified_other_slides.append(old_slide.slide_number)

    if modified_other_slides:
        return f"Unintended changes detected in slides: {modified_other_slides}", 0.0

    # Load presentations to verify content changes
    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        if len(original_prs.slides) != len(modified_prs.slides):
            return f"Number of slides changed: {len(original_prs.slides)} -> {len(modified_prs.slides)}", 0.0

        # Check slides other than slide 2 (index 1)
        changes_detected = 0
        for i, (orig_slide, mod_slide) in enumerate(zip(original_prs.slides, modified_prs.slides)):
            if i == 1:  # Skip slide 2 (index 1)
                continue

            # Compare slide layouts
            if orig_slide.slide_layout.name != mod_slide.slide_layout.name:
                changes_detected += 1
                continue

            # Compare number of shapes
            if len(orig_slide.shapes) != len(mod_slide.shapes):
                changes_detected += 1
                continue

        if changes_detected > 0:
            return f"Detected changes in {changes_detected} other slides", 0.5

        return "No unintended changes detected in other slides", 1.0

    except Exception as e:
        return f"Error checking other slides: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        if len(original_prs.slides) < 2 or len(modified_prs.slides) < 2:
            return "Slide 2 not found in one of the presentations", 0.0

        orig_slide = original_prs.slides[1]  # Slide 2 (0-indexed)
        mod_slide = modified_prs.slides[1]

        # Compare slide layout
        if orig_slide.slide_layout.name != mod_slide.slide_layout.name:
            return "Slide 2 layout was changed", 0.0

        # Compare number of shapes (excluding background)
        orig_shapes = [s for s in orig_slide.shapes if s.shape_type != 14]  # Exclude background
        mod_shapes = [s for s in mod_slide.shapes if s.shape_type != 14]

        if len(orig_shapes) != len(mod_shapes):
            return f"Number of shapes changed on slide 2: {len(orig_shapes)} -> {len(mod_shapes)}", 0.5

        # Compare text content in shapes
        text_changes = 0
        for orig_shape, mod_shape in zip(orig_shapes, mod_shapes):
            if hasattr(orig_shape, 'text') and hasattr(mod_shape, 'text'):
                if orig_shape.text != mod_shape.text:
                    text_changes += 1

        if text_changes > 0:
            return f"Text content changed in {text_changes} shapes on slide 2", 0.5

        return "Slide 2 content preserved (only background changed)", 1.0

    except Exception as e:
        return f"Error checking slide 2 content: {str(e)}", 0.5
